wss.on('connection', (ws, req) => {
  const origin = req.headers.origin;
  if (!ALLOWED_ORIGINS.includes(origin)) {
    ws.close(1008, 'Origin not allowed');
    return;
  }
  ws.on('message', handleMessage);
});

// Graceful close with code and reason
ws.close(1000, 'Session ended');

// Force terminate only after timeout
setTimeout(() => {
  if (ws.readyState !== WebSocket.CLOSED) {
    ws.terminate();
  }
}, 5000);

const HEARTBEAT_INTERVAL = 30000;

function heartbeat() {
  this.isAlive = true;
}

wss.on('connection', (ws) => {
  ws.isAlive = true;
  ws.on('pong', heartbeat);
});

setInterval(() => {
  wss.clients.forEach((ws) => {
    if (!ws.isAlive) return ws.terminate();
    ws.isAlive = false;
    ws.ping();
  });
}, HEARTBEAT_INTERVAL);

function reconnect(attempt = 0) {
  const delay = Math.min(1000 * 2 ** attempt, 30000);
  const jitter = delay * 0.5 * Math.random();
  setTimeout(() => {
    const ws = new WebSocket(url);
    ws.onerror = () => reconnect(attempt + 1);
  }, delay + jitter);
}

ws.on('message', (raw) => {
  const msg = JSON.parse(raw);
  handlers[msg.type](msg.payload); // No validation
});

ws.on('message', (raw) => {
  let msg;
  try {
    msg = messageSchema.parse(JSON.parse(raw));
  } catch (e) {
    ws.send(JSON.stringify({ error: 'Invalid message format' }));
    return;
  }
  handlers[msg.type]?.(msg.payload);
});

const wss = new WebSocket.Server({
  port: 8080,
  maxPayload: 64 * 1024, // 64KB limit
});

server.on('upgrade', (req, socket, head) => {
  const token = new URL(req.url, 'http://x').searchParams.get('token');
  const user = verifyToken(token);
  if (!user) {
    socket.write('HTTP/1.1 401 Unauthorized\r\n\r\n');
    socket.destroy();
    return;
  }
  wss.handleUpgrade(req, socket, head, (ws) => {
    ws.user = user;
    wss.emit('connection', ws, req);
  });
});

function safeSend(ws, data) {
  if (ws.bufferedAmount > MAX_BUFFER) {
    logger.warn('Slow consumer, dropping message');
    return;
  }
  ws.send(data);
}
